// === 1) Normalize incoming form fields ===
// Website form posts multipart/form-data; text fields can land at
// root or under .body — handle both. Output uses the exact labels
// the existing Pricing Engine expects.
const raw = $input.first().json;
const body = (raw && raw.body && typeof raw.body === 'object') ? raw.body : raw;
const toNum = (v) => { const n = parseFloat(v); return Number.isFinite(n) ? n : 0; };

return [{
  json: {
    'Full Name':                    String(body['Full Name'] || '').trim(),
    'Email':                        String(body['Email'] || '').trim(),
    'Phone Number':                 String(body['Phone Number'] || '').trim(),
    'ZIP Code':                     toNum(body['ZIP Code']),
    'Property Address (optional)':  String(body['Property Address (optional)'] || '').trim(),
    'Property Type':                String(body['Property Type'] || '').trim(),
    'Service':                      String(body['Service'] || '').trim(),
    'Quantity (panes / sq ft / linear ft / panels / loads — depends on service)':
                                    toNum(body['Quantity (panes / sq ft / linear ft / panels / loads — depends on service)']),
    'Condition':                    String(body['Condition'] || '').trim(),
    'Access':                       String(body['Access'] || '').trim(),
    'Urgency':                      String(body['Urgency'] || '').trim(),
    'LA Logistics':                 String(body['LA Logistics'] || '').trim(),
    'Recurring':                    String(body['Recurring'] || '').trim(),
    'Project Notes (optional)':     String(body['Project Notes (optional)'] || '').trim(),
    'Photos (optional — upload for a more accurate estimate)': []
  }
}];

// === 2) Pull image files out of the webhook item's binary bag ===
// Convert each to a data URL OpenAI's Vision API accepts.
const webhookItem = $('Webhook').first();
const binary = webhookItem.binary || {};
const formData = $input.first().json;

const photos = [];
for (const key of Object.keys(binary)) {
  const b = binary[key];
  if (!b || !b.mimeType || !b.mimeType.startsWith('image/')) continue;
  photos.push({
    type: 'image_url',
    image_url: {
      url: `data:${b.mimeType};base64,${b.data}`,
      detail: 'low'
    }
  });
}

return [{
  json: {
    ...formData,
    has_photos: photos.length > 0,
    photo_count: photos.length,
    photos_for_ai: photos
  }
}];

// === 3) Build OpenAI Vision request — all photos in one call ===
const data = $input.first().json;

const systemPrompt = `You are a property assessment assistant for Squeegee Squad LA, a Los Angeles cleaning services company. You analyze customer-submitted photos and return ONLY a JSON object matching this exact schema:

{
  "quantity_estimate": <number or null — panes, sq ft, panels, linear ft of the implied unit; null if undetectable>,
  "quantity_unit": "<panes | sqft | panels | linear ft | empty string>",
  "stories": <integer 1-10 or null>,
  "condition": "<Standard | Moderate buildup/staining | Heavy buildup/staining | Severe/restoration | empty string>",
  "access": "<Easy | Moderate | Difficult | Height/Lift/Rope | empty string>",
  "risk_factors": ["short string per visible risk"],
  "confidence": "<High | Medium | Low>",
  "reasoning": "<one sentence — what you saw>"
}

GUIDELINES:
- Use "Standard" when surface looks clean.
- Use "Moderate buildup/staining" for visible dirt, water spots, mild grime.
- Use "Heavy buildup/staining" for significant grime, staining, mold, or residue.
- Use "Severe/restoration" ONLY for caked-on damage or restoration work.
- "Height/Lift/Rope" access is for 4+ stories or any high-rise.
- Be CONSERVATIVE with quantity — under-estimate rather than guess high.
- Confidence "Low" if photos are blurry, dark, partial.
- Return ONLY the JSON. No prose, no markdown fences.`;

const userText = `The customer selected service: "${data['Service']}". Property Type: "${data['Property Type']}". Please analyze the ${data.photo_count} attached photo(s).`;

const openaiPayload = {
  model: 'gpt-4o',
  response_format: { type: 'json_object' },
  max_tokens: 600,
  temperature: 0.2,
  messages: [
    { role: 'system', content: systemPrompt },
    {
      role: 'user',
      content: [
        { type: 'text', text: userText },
        ...data.photos_for_ai
      ]
    }
  ]
};

return [{ json: { ...data, openai_payload: openaiPayload } }];

// === 4) Parse AI response and ENRICH form ===
// Rule: only fill BLANK fields — never override what the customer typed.
// Stash AI metadata so the dashboard log + team can audit AI suggestions.
const formData = $('Prepare OpenAI Request').first().json;
const aiResp = $input.first().json;

let aiResult = {};
try {
  const content = aiResp?.choices?.[0]?.message?.content || '{}';
  aiResult = JSON.parse(content);
} catch (e) {
  aiResult = { error: 'Failed to parse AI response' };
}

const enriched = { ...formData };

if (!enriched['Condition'] && aiResult.condition) {
  enriched['Condition'] = aiResult.condition;
  enriched.ai_filled_condition = true;
}
if (!enriched['Access'] && aiResult.access) {
  enriched['Access'] = aiResult.access;
  enriched.ai_filled_access = true;
}
const qtyKey = 'Quantity (panes / sq ft / linear ft / panels / loads — depends on service)';
if ((!enriched[qtyKey] || enriched[qtyKey] === 0) && aiResult.quantity_estimate) {
  enriched[qtyKey] = aiResult.quantity_estimate;
  enriched.ai_filled_quantity = true;
}

// Photos flag drives the §10 confidence boost downstream.
enriched['Photos (optional — upload for a more accurate estimate)'] = ['photo'];

// Stash AI metadata for dashboard logging.
enriched.ai_analysis_done = true;
enriched.ai_reasoning = aiResult.reasoning || '';
enriched.ai_risk_factors = Array.isArray(aiResult.risk_factors) ? aiResult.risk_factors.join('; ') : '';
enriched.ai_confidence = aiResult.confidence || '';
enriched.ai_quantity_estimate = aiResult.quantity_estimate || '';
enriched.ai_stories = aiResult.stories || '';

return [{ json: enriched }];

// No-photos path: stamp the AI metadata fields with empties so the
// downstream Pricing Engine + dashboard log have a consistent shape.
const data = $input.first().json;
return [{
  json: {
    ...data,
    ai_analysis_done: false,
    ai_reasoning: '',
    ai_risk_factors: '',
    ai_confidence: '',
    ai_quantity_estimate: '',
    ai_stories: ''
  }
}];

// === Squeegee Squad LA — Pricing Engine (Public Website + Vision) ===
// PATCH: reads from `Merge Photo Branches` instead of the missing
// `Public Website Form` node. Also pulls AI metadata through to the
// dashboard log + customer copy.
const form = $('Merge Photo Branches').first().json;
const allRules = $('Get Pricing Rule').all().map(i => i.json);
const rule = allRules.find(r => String(r['Service']).trim() === String(form['Service']).trim());
const multipliers = $('Get Multipliers').all().map(i => i.json);
const territories = $('Get Territory Modifiers').all().map(i => i.json);
const smartDefaultsRows = $('Get Smart Defaults').all().map(i => i.json);
const sdRow = smartDefaultsRows.find(r => String(r['Property Type']).trim() === String(form['Property Type']).trim()) || {};
const defaultedFields = [];
const resolve = (formKey, sdKey) => {
  const raw = form[formKey];
  const v = (raw === undefined || raw === null) ? '' : String(raw).trim();
  if (v) return v;
  defaultedFields.push(sdKey);
  return sdRow[sdKey] ? String(sdRow[sdKey]).trim() : '';
};
const resolvedCondition = resolve('Condition', 'Condition');
const resolvedAccess    = resolve('Access', 'Access');
const resolvedUrgency   = resolve('Urgency', 'Urgency');
const resolvedLogistics = resolve('LA Logistics', 'LA Logistics');
const resolvedRecurring = resolve('Recurring', 'Recurring');
const scoringRows = $('Get Scoring Rules').all().map(i => i.json);

if (!rule) {
  throw new Error(`No pricing rule found for service: ${form['Service']}. Check the Developer Pricing Rules tab.`);
}

const lookupMult = (category, option) => {
  const row = multipliers.find(r =>
    String(r['Multiplier Category']).trim() === category &&
    String(r['Option']).trim() === String(option).trim()
  );
  return row ? parseFloat(row['Multiplier']) : 1;
};

const min = parseFloat(rule['Minimum']) || 0;
const lowRate = parseFloat(rule['Low Unit Rate']) || 0;
const highRate = parseFloat(rule['High Unit Rate']) || 0;
const qty = parseFloat(form['Quantity (panes / sq ft / linear ft / panels / loads — depends on service)']) || 0;

const baseLow = Math.max(min, qty * lowRate);
const baseHigh = Math.max(min, qty * highRate);

const condMult   = lookupMult('Condition', resolvedCondition);
const propMult   = lookupMult('Property Type', form['Property Type']);
const accessMult = lookupMult('Access', resolvedAccess);
const urgMult    = lookupMult('Urgency', resolvedUrgency);
const logMult    = lookupMult('LA Logistics', resolvedLogistics);
const recMult    = lookupMult('Recurring', resolvedRecurring);

const terrRow = territories.find(r => String(r['ZIP']).trim() === String(form['ZIP Code']).trim());
const territoryMult = terrRow ? parseFloat(terrRow['Modifier']) : 1;

const combined = condMult * propMult * accessMult * urgMult * logMult * recMult * territoryMult;
const passThrough = 0;

const rangeWidthRaw = String(rule['Range Width'] || '').trim();
const rangeWidthMatch = rangeWidthRaw.match(/(\d+(?:\.\d+)?)%?\s*[-–—]\s*(\d+(?:\.\d+)?)%?/);
let scaledLow, scaledHigh, widthUsedPct = null;
if (rangeWidthMatch) {
  const widthLow = parseFloat(rangeWidthMatch[1]) / 100;
  const widthHigh = parseFloat(rangeWidthMatch[2]) / 100;
  widthUsedPct = (widthLow + widthHigh) / 2;
  const midBase = (baseLow + baseHigh) / 2;
  const half = widthUsedPct / 2;
  scaledLow  = midBase * (1 - half);
  scaledHigh = midBase * (1 + half);
} else {
  scaledLow  = baseLow;
  scaledHigh = baseHigh;
}

const estLowInitial = Math.round(scaledLow * combined + passThrough);
const estHighInitial = Math.round(scaledHigh * combined + passThrough);

const alwaysLowServices = [
  'Parking Garage Deep Cleaning', 'Trash Chute Cleaning', 'Post-Construction Cleanup',
  'Warehouse Cleaning', 'High-Access/Lift Window Cleaning', 'Large Junk Removal',
  'Eviction / Turnover Cleanouts', 'Property Cleanouts'
];
const photos = form['Photos (optional — upload for a more accurate estimate)'];
const hasPhotos = Array.isArray(photos) ? photos.length > 0 : !!photos;
const notesText = String(form['Project Notes (optional)'] || '').trim();
const hasNotes = notesText.length > 0;
const hasEvidence = hasPhotos || hasNotes;
const isComplexJob = alwaysLowServices.includes(form['Service']) ||
  resolvedCondition === 'Severe/restoration' ||
  resolvedAccess === 'Height/Lift/Rope' ||
  ['Water Runoff/Containment', 'Special Handling'].includes(resolvedLogistics);

let estLow = estLowInitial;
let estHigh = estHighInitial;
if (hasEvidence && !isComplexJob) {
  estLow = Math.round(estLowInitial * 1.05);
  estHigh = Math.round(estHighInitial * 0.95);
}

const multiplierBreakdown = [];
if (condMult !== 1)      multiplierBreakdown.push(`${condMult}× cond`);
if (propMult !== 1)      multiplierBreakdown.push(`${propMult}× property`);
if (accessMult !== 1)    multiplierBreakdown.push(`${accessMult}× access`);
if (urgMult !== 1)       multiplierBreakdown.push(`${urgMult}× urgency`);
if (logMult !== 1)       multiplierBreakdown.push(`${logMult}× logistics`);
if (recMult !== 1)       multiplierBreakdown.push(`${recMult}× recurring`);
if (territoryMult !== 1) multiplierBreakdown.push(`${territoryMult}× territory`);
const multiplierDetail = multiplierBreakdown.length ? ` (${multiplierBreakdown.join(' × ')})` : '';
const passText = passThrough ? ` + $${passThrough} pass-through` : '';
const rangeWidthNote = (widthUsedPct !== null) ? ` [width ${Math.round(widthUsedPct*100)}% from sheet "${rangeWidthRaw}"]` : '';
let rangeMath = `Base $${Math.round(baseLow)}-$${Math.round(baseHigh)}${rangeWidthNote} × ${combined.toFixed(3)}x${multiplierDetail}${passText} = $${estLowInitial}-$${estHighInitial}`;
if (hasEvidence && !isComplexJob) {
  const evidenceLabel = hasPhotos && hasNotes ? 'photos+notes' : (hasPhotos ? 'photos' : 'notes');
  rangeMath += ` → ${evidenceLabel} tightened to $${estLow}-$${estHigh}`;
}

const subPayoutLow = Math.round(estLow * 0.45);
const subPayoutHigh = Math.round(estHigh * 0.45);
const grossLow = estLow - subPayoutLow;
const grossHigh = estHigh - subPayoutHigh;

const MARGIN_THRESHOLD = 0.35;
const effectiveGrossLow = grossLow - passThrough;
const effectiveMarginRatio = effectiveGrossLow / Math.max(estLow, 1);
const lowMargin = effectiveMarginRatio < MARGIN_THRESHOLD;

let confidence = rule['Default Confidence'] || 'Medium';
if (resolvedCondition === 'Severe/restoration') confidence = 'Low';
if (resolvedAccess === 'Height/Lift/Rope') confidence = 'Low';
if (alwaysLowServices.includes(form['Service'])) confidence = 'Low';
if (confidence === 'High') {
  const softMediumTriggers = (
    resolvedCondition === 'Moderate buildup/staining' ||
    resolvedCondition === 'Heavy buildup/staining'    ||
    form['Property Type'] === 'Commercial'            ||
    resolvedAccess === 'Difficult'
  );
  if (softMediumTriggers) confidence = 'Medium';
}
if (hasEvidence && confidence === 'Medium' && !isComplexJob) confidence = 'High';
if (!hasEvidence && isComplexJob) {
  if (confidence === 'High') confidence = 'Medium';
  else if (confidence === 'Medium') confidence = 'Low';
}
if (defaultedFields.length >= 2) {
  if (confidence === 'High') confidence = 'Medium';
  else if (confidence === 'Medium') confidence = 'Low';
}

const getThreshold = (key) => {
  const row = scoringRows.find(r => String(r['Type']).trim() === 'Threshold' && String(r['Key']).trim() === key);
  return row ? parseFloat(row['Value']) : null;
};
const tLow = getThreshold('Low Priority Max') ?? 300;
const tStd = getThreshold('Standard Max') ?? 750;
const tGood = getThreshold('Good Max') ?? 2500;
const tHigh = getThreshold('High Value Max') ?? 7500;
const label = estLow < tLow ? 'Low Priority' :
              estLow < tStd ? 'Standard'     :
              estLow < tGood ? 'Good'        :
              estLow < tHigh ? 'High Value'  : 'Priority';

const strategicTypes = scoringRows
  .filter(r => String(r['Type']).trim() === 'Strategic' && String(r['Value']).trim().toUpperCase() === 'YES')
  .map(r => String(r['Key']).trim());
const strategicAccount = strategicTypes.includes(form['Property Type']);

const recurringMap = {};
scoringRows.filter(r => String(r['Type']).trim() === 'Recurring').forEach(r => {
  recurringMap[String(r['Key']).trim()] = String(r['Value']).trim();
});
const serviceRecurringTier = recurringMap[form['Service']];
let recurringScore;
if (strategicAccount && serviceRecurringTier === 'Very High') recurringScore = 'Very High';
else if (strategicAccount) recurringScore = 'High';
else if (serviceRecurringTier === 'Medium') recurringScore = 'Medium';
else recurringScore = 'Low';

let reviewLogic = String(rule['Review Logic'] || '');
const reviewFlag = confidence === 'Low' || /always review/i.test(reviewLogic) || lowMargin;
if (lowMargin) {
  const pct = Math.round(effectiveMarginRatio * 100);
  reviewLogic = (reviewLogic ? reviewLogic + '; ' : '') + `LOW MARGIN — effective gross ${pct}% (threshold ${Math.round(MARGIN_THRESHOLD * 100)}%)`;
}

const copyRows = $('Get Customer Copy').all().map(i => i.json);
const copyRow = copyRows.find(r => String(r['Key']).trim() === 'public');
const customerCopyTemplate = copyRow ? String(copyRow['Template']) :
  `Hi ${form['Full Name']}, your preliminary estimate range is $${estLow.toLocaleString()} - $${estHigh.toLocaleString()}.`;
const customerCopy = customerCopyTemplate
  .replace('{LOW}', estLow.toLocaleString())
  .replace('{HIGH}', estHigh.toLocaleString())
  .replace('{NAME}', form['Full Name'] || '');

const bundleRows = $('Get Bundle Logic').all().map(i => i.json);
const bundleCategoryMap = {
  'Residential Window Cleaning':       'Window Cleaning',
  'Large/Luxury Residential Windows':  'Window Cleaning',
  'Dumpster Pad Sanitization':         'Dumpster Pad',
  'Trash Area Cleaning':               'Dumpster Pad',
  'Post-Construction Cleanup':         'Post-Construction',
  'Parking Garage Deep Cleaning':      'Parking Garage'
};
const bundleCategory = bundleCategoryMap[form['Service']];
let bundleRecommendation = '';
if (bundleCategory) {
  const findTier = (tier) => bundleRows.find(r =>
    String(r['Service']).trim() === bundleCategory &&
    String(r['Package Tier']).trim() === tier
  );
  const g = findTier('Good'), b = findTier('Better'), best = findTier('Best');
  const parts = [];
  if (g)    parts.push(`• Good: ${g['Description']} (${g['Example Range']})`);
  if (b)    parts.push(`• Better: ${b['Description']} (${b['Example Range']})`);
  if (best) parts.push(`• Best: ${best['Description']} (${best['Example Range']})`);
  if (parts.length) {
    bundleRecommendation = '\n\n---\n**RECOMMENDED PACKAGES**\n' + parts.join('\n') + '\n\nAsk about upgrading for better value.';
  }
}

return [{
  json: {
    leadId: `SS-${Date.now()}`,
    timestamp: new Date().toISOString(),
    mode: form.ai_analysis_done ? 'Public Website + Vision' : 'Public Website',

    customer_name:  form['Full Name'],
    customer_email: form['Email'],
    customer_phone: form['Phone Number'],
    lead_source:    'website',
    zip:            form['ZIP Code'],
    address:        form['Property Address (optional)'],
    property_type:  form['Property Type'],
    service:        form['Service'],
    quantity:       qty,
    condition:      resolvedCondition,
    access:         resolvedAccess,
    urgency:        resolvedUrgency,
    la_logistics:   resolvedLogistics,
    recurring:      resolvedRecurring,
    pass_through:   passThrough,
    photos_uploaded: hasPhotos ? 'Yes' : 'No',
    notes_provided:  hasNotes ? 'Yes' : 'No',
    notes:          form['Project Notes (optional)'] || '',

    ai_analysis_done:    form.ai_analysis_done ? 'YES' : 'NO',
    ai_reasoning:        form.ai_reasoning || '',
    ai_risk_factors:     form.ai_risk_factors || '',
    ai_confidence:       form.ai_confidence || '',
    ai_filled_condition: form.ai_filled_condition ? 'YES' : 'NO',
    ai_filled_access:    form.ai_filled_access ? 'YES' : 'NO',
    ai_filled_quantity:  form.ai_filled_quantity ? 'YES' : 'NO',

    estimate_low: estLow,
    estimate_high: estHigh,
    sub_payout_low: subPayoutLow,
    sub_payout_high: subPayoutHigh,
    gross_low: grossLow,
    gross_high: grossHigh,
    confidence,
    priority_label: label,
    strategic_account: strategicAccount ? 'YES' : 'NO',
    recurring_score: recurringScore,
    review_flag: reviewFlag ? 'YES' : 'NO',
    review_logic: reviewLogic,
    defaulted_fields: defaultedFields.join(', ') || 'None',
    defaulted_count: defaultedFields.length,
    customer_copy: customerCopy,
    bundle_recommendation: bundleRecommendation,
    range_math: rangeMath
  }
}];
